// Classic fork pattern: parent creates one child
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/wait.h>

int main() {
    pid_t pid = fork();
    if (pid == -1) {
        perror("fork");
        exit(1);
    }
    if (pid == 0) {
        // Child process
        printf("Child: PID=%d, PPID=%d\n", getpid(), getppid());
        exit(42);  // terminate with code 42
    }
    // Parent process
    int wstatus;
    pid_t w = wait(&wstatus);
    if (WIFEXITED(wstatus)) {
        printf("Parent: child %d exited with %d\n",
               w, WEXITSTATUS(wstatus));
    }
    return 0;
}

// Creating N children with a loop
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/wait.h>

int main() {
    int N = 3;
    for (int i = 0; i < N; i++) {
        pid_t pid = fork();
        if (pid == -1) { perror("fork"); exit(1); }
        if (pid == 0) {
            // Child i
            printf("Child %d: PID=%d\n", i, getpid());
            exit(i);
        }
    }
    // Parent waits for all children
    for (int i = 0; i < N; i++) {
        int wstatus;
        pid_t w = wait(&wstatus);
        printf("Child %d terminated\n", w);
    }
    return 0;
}
